function validArrangement(pairs) {
    let graph = new Map();
    for (let pair of pairs) {
        if (!graph.has(pair[0])) {
            graph.set(pair[0], []);
        }
        graph.get(pair[0]).push(pair[1]);
    }
    let result = [];
    let current = pairs[0][0];
    while (graph.size) {
        let pair = [current, graph.get(current).pop()];
        if (graph.get(current).length === 0) {
            graph.delete(current);
        }
        result.push(pair);
        current = pair[1];
    }
    return result;
}
```


