import java.util.List;
import java.util.ArrayList;
import java.util.Map;
import java.util.HashMap;

public List<List<Integer>> validArrangement(List<List<Integer>> pairs) {
    Map<Integer, List<Integer>> graph = new HashMap<>();
    for (List<Integer> pair : pairs) {
        graph.putIfAbsent(pair.get(0), new ArrayList<>());
        graph.get(pair.get(0)).add(pair.get(1));
    }
    List<List<Integer>> result = new ArrayList<>();
    int current = pairs.get(0).get(0);
    while (!graph.isEmpty()) {
        List<Integer> temp = new ArrayList<>();
        temp.add(current);
        temp.add(graph.get(current).remove(graph.get(current).size()-1));
        if (graph.get(current).isEmpty()) graph.remove(current);
        result.add(temp);
        current = temp.get(1);
    }
    return result;
}
```


